parameters.jsCode:
// OCR Gate — Apply Response
// Inputs (via $input.all()):
//   index 0: the OCR service response (HTTP Request node output)
// Inputs (via $items('Merge')):
//   the original merged payload we want to forward to Route.
//
// Behaviour:
//   handled=false              -> pass original payload through untouched
//   handled=true, done=false   -> emit nothing (stop the run; OCR already replied)
//   handled=true, done=true    -> rewrite messages[0] as plain text with injected_text,
//                                 set mode to resume_mode, then continue to Route.

const gateItems = $input.all();
const gate = (gateItems[0] && gateItems[0].json) || {};

// Get the original payload we need to forward to Route.
// Prefer the last 'Merge' output; fall back to the gate item if present.
let originalItems = [];
try {
  originalItems = $items('Merge');
} catch (_) {
  originalItems = [];
}
const original = (originalItems[0] && originalItems[0].json)
  || (gateItems[0] && gateItems[0].json && gateItems[0].json.__original)
  || {};

// 1) Not handled -> pass through.
if (!gate || gate.handled !== true) {
  return [{ json: original }];
}

// 2) Handled but not done -> stop.
if (gate.done !== true) {
  return [];
}

// 3) Handled and done -> inject the confirmed list as a user text message.
const injected = String(gate.injected_text || '').trim();
if (!injected) {
  // Defensive: if the service marked done without text, just pass through.
  return [{ json: original }];
}

const cloned = JSON.parse(JSON.stringify(original || {}));
cloned.messages = Array.isArray(cloned.messages) ? cloned.messages : [];
const msg = cloned.messages[0] || {};
msg.type = 'text';
msg.text = { body: injected };
delete msg.image;
delete msg.audio;
delete msg.voice;
delete msg.interactive;
delete msg.button;
cloned.messages[0] = msg;

// Carry back the mode the user was in, so Route's 'already in mode' branch fires.
if (gate.resume_mode) {
  cloned.mode = gate.resume_mode;
}

// Mark so downstream can detect an OCR-injected message if ever needed.
cloned._ocr = {
  injected: true,
  resume_mode: gate.resume_mode || null,
  at: new Date().toISOString()
};

return [{ json: cloned }];
